def validate_11_step_structure(script_sections: list) -> dict: """Validate 11-step structure is complete.""" required_steps = [ "hook", "lead", "rock_bottom", "authority", "ump", "ums", "product", "testimonials", "offer", "urgency", "cta" ]
present = [s.get("name", "").lower() for s in script_sections] missing = [step for step in required_steps if step not in present]
return { "passed": len(missing) == 0, "steps_present": len(present), "missing_steps": missing, "recommendation": f"Add missing sections: {', '.join(missing)}" if missing else None }


def validate_mechanism_before_product(script_sections: list) -> dict:
    """Ensure mechanism education precedes product reveal."""
    section_order = [s.get("name", "").lower() for s in script_sections]

    ump_index = section_order.index("ump") if "ump" in section_order else -1
    ums_index = section_order.index("ums") if "ums" in section_order else -1
    product_index = section_order.index("product") if "product" in section_order else -1

    issues = []
    if ump_index == -1:
        issues.append("UMP section missing")
    if ums_index == -1:
        issues.append("UMS section missing")
    if product_index != -1 and ump_index != -1 and product_index < ump_index:
        issues.append("Product revealed before UMP")
    if product_index != -1 and ums_index != -1 and product_index < ums_index:
        issues.append("Product revealed before UMS")

    return {
        "passed": len(issues) == 0,
        "issues": issues,
        "recommendation": "Mechanism must be established before product reveal"
    }


def validate_visual_scripting(script_sections: list) -> dict:
    """Check all sections have visual specifications."""
    missing_visuals = []

    for i, section in enumerate(script_sections):
        has_visual = section.get("has_visual_cue", False)
        has_overlay = section.get("has_text_overlay", False)

        if not has_visual:
            missing_visuals.append(f"Section {i+1} ({section.get('name', 'unknown')}): No visual cue")

    return {
        "passed": len(missing_visuals) == 0,
        "sections_with_visuals": len(script_sections) - len(missing_visuals),
        "missing": missing_visuals,
        "recommendation": "Every section needs [VISUAL: ...] specification"
    }


def check_compliance_language(script_text: str) -> dict:
    """Flag risky health/result language."""
    risky_patterns = [
        "cure", "treat", "reverse", "heal", "guaranteed results",
        "100%", "everyone", "miracle", "breakthrough"
    ]

    flagged = []
    script_lower = script_text.lower()

    for pattern in risky_patterns:
        if pattern in script_lower:
            flagged.append({
                "pattern": pattern,
                "risk": "High - potential compliance violation",
                "suggestion": f"Replace '{pattern}' with qualified language"
            })

    return {
        "passed": len(flagged) == 0,
        "flagged_count": len(flagged),
        "flagged": flagged,
        "recommendation": "Use 'may help', 'supports', 'designed to' instead"
    }

def calculate_belief_pitch_ratio(script_sections: list) -> dict: """Calculate belief-building vs pitch ratio.""" belief_sections = ["hook", "lead", "rock_bottom", "authority", "ump", "ums", "testimonials"] pitch_sections = ["product", "offer", "urgency", "cta"]
belief_time = 0 pitch_time = 0
for section in script_sections: name = section.get("name", "").lower() duration = section.get("duration_seconds", 60)
if name in belief_sections: belief_time += duration elif name in pitch_sections: pitch_time += duration
total_time = belief_time + pitch_time belief_ratio = belief_time / total_time if total_time > 0 else 0
return { "passed": belief_ratio >= 0.75, "belief_percentage": round(belief_ratio * 100, 1), "pitch_percentage": round((1 - belief_ratio) * 100, 1), "target": "80% belief, 20% pitch", "recommendation": "Add more mechanism education" if belief_ratio < 0.75 else None }
